package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVParserTest {

    private CSVParser parserMock;
    private CSVFormat formatMock;
    private Reader readerMock;

    @BeforeEach
    public void setup() {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);
        parserMock = Mockito.spy(new CSVParser(readerMock, formatMock));
    }

    @Test
    public void testGetRecords_noArg_callsGetRecordsWithList() throws Exception {
        // Arrange
        List<CSVRecord> expectedList = new ArrayList<>();
        doReturn(expectedList).when(parserMock).getRecords(any());

        // Act
        List<CSVRecord> actual = parserMock.getRecords();

        // Assert
        assertSame(expectedList, actual);
        verify(parserMock).getRecords(any());
    }

    @Test
    public void testGetRecords_withList_argumentAndReturn() throws Exception {
        // Arrange
        List<CSVRecord> records = new ArrayList<>();
        // Use reflection to invoke private getRecords(List)
        Method getRecordsListMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsListMethod.setAccessible(true);

        // Act
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsListMethod.invoke(parserMock, records);

        // Assert
        assertNotNull(result);
        assertSame(records, result);
    }

    @Test
    public void testGetRecords_withList_reflectInvokePrivate_getRecords() throws Exception {
        // Arrange
        List<CSVRecord> inputList = new ArrayList<>();

        // Setup the lexer mock to simulate token reading.
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        Lexer lexerMock = mock(Lexer.class);
        lexerField.set(parserMock, lexerMock);

        Field reusableTokenField = CSVParser.class.getDeclaredField("reusableToken");
        reusableTokenField.setAccessible(true);

        Class<?> tokenClass = Class.forName("org.apache.commons.csv.Token");
        Object tokenMock = mock(tokenClass);
        reusableTokenField.set(parserMock, tokenMock);

        Class<?> tokenTypeClass = Class.forName("org.apache.commons.csv.Token$Type");
        Object tokenTypeTOKEN = Enum.valueOf((Class<Enum>) tokenTypeClass, "TOKEN");
        Object tokenTypeEOF = Enum.valueOf((Class<Enum>) tokenTypeClass, "EOF");

        // Setup when(tokenMock.getType()) to return TOKEN then EOF
        Method getTypeMethod = tokenClass.getMethod("getType");
        when(getTypeMethod.invoke(tokenMock)).thenReturn(tokenTypeTOKEN);

        // Use Mockito's Answer to simulate getType returning TOKEN then EOF
        // Since we cannot directly do when(tokenMock.getType()), use doAnswer on getType method call via spy
        // Instead, use Mockito to stub getType() on tokenMock:
        // Cast tokenMock to tokenClass and stub getType()
        when(tokenClass.cast(tokenMock).getClass().getMethod("getType").invoke(tokenMock)).thenReturn(tokenTypeTOKEN);

        // But this is complicated, so better to use Mockito's 'when' with a spy or Answer:

        // Use Mockito's doAnswer for getType method on tokenMock:
        org.mockito.stubbing.Answer<Object> answer = new org.mockito.stubbing.Answer<Object>() {
            private int count = 0;

            @Override
            public Object answer(org.mockito.invocation.InvocationOnMock invocation) {
                if (count == 0) {
                    count++;
                    return tokenTypeTOKEN;
                } else {
                    return tokenTypeEOF;
                }
            }
        };
        // Use Mockito to stub getType() on tokenMock:
        // Mockito cannot stub methods on Object, so cast tokenMock to tokenClass and spy it
        Object tokenSpy = Mockito.spy(tokenMock);
        reusableTokenField.set(parserMock, tokenSpy);
        when(tokenClass.cast(tokenSpy).getClass().getMethod("getType").invoke(tokenSpy)).thenCallRealMethod();
        // Instead, use Mockito doAnswer on tokenSpy.getType():
        // But cannot directly call getType() since tokenClass is unknown at compile-time
        // Use Mockito's doAnswer with reflection:
        // We can use Mockito's doAnswer on tokenSpy.getType() by using a helper interface:

        // Define helper interface for Token with getType method
        interface TokenHelper {
            Object getType();
            String getContent();
            boolean isReady();
        }

        TokenHelper tokenHelperMock = mock(TokenHelper.class);
        reusableTokenField.set(parserMock, tokenHelperMock);

        when(tokenHelperMock.getType()).thenReturn(tokenTypeTOKEN, tokenTypeEOF);
        when(tokenHelperMock.getContent()).thenReturn("value1");
        when(tokenHelperMock.isReady()).thenReturn(true);

        // Setup lexer.nextToken to update reusableToken and simulate tokens
        doAnswer(invocation -> {
            // simulate first call returns TOKEN
            when(tokenHelperMock.getType()).thenReturn(tokenTypeTOKEN);
            return null;
        }).doAnswer(invocation -> {
            // simulate second call returns EOF
            when(tokenHelperMock.getType()).thenReturn(tokenTypeEOF);
            return null;
        }).when(lexerMock).nextToken(tokenHelperMock);

        // Act
        Method getRecordsListMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsListMethod.setAccessible(true);
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsListMethod.invoke(parserMock, inputList);

        // Assert
        assertNotNull(result);
        assertSame(inputList, result);
    }
}
